<?php
if (!function_exists('hr_t')) {
  function hr_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('hr_h')) {
  function hr_h($key, $fallback = '') { return htmlspecialchars((string) hr_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('hr_js')) {
  function hr_js($key, $fallback = '') { return json_encode(hr_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
if (session_status() === PHP_SESSION_NONE) session_start();
include "../../inc/config.php";
session_check_json();
function pyp_json($s,$m='',$x=array()){header('Content-Type: application/json; charset=utf-8');$p=array('status'=>$s);if($m!=='')$p[$s==='good'?'message':'error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function pyp_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function pyp_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;}
function pyp_g($k,$d=''){return isset($_GET[$k])?$_GET[$k]:$d;}
function pyp_c($v){return strtoupper(trim((string)$v));}
function pyp_user(){return isset($_SESSION['username'])&&$_SESSION['username']!==''?$_SESSION['username']:'system';}
function pyp_num($v){return is_numeric($v)?(float)$v:0;}
function pyp_date_ok($d){return (bool)preg_match('/^\d{4}-\d{2}-\d{2}$/',(string)$d);}
function pyp_select2($rows,$id,$cb){$out=array();foreach($rows as $r)$out[]=array('id'=>$r->$id,'text'=>$cb($r));header('Content-Type: application/json; charset=utf-8');echo json_encode(array('results'=>$out));exit;}
function pyp_table_exists($name){global $db;$r=$db->fetch("SHOW TABLES LIKE ?",array($name));return (bool)$r;}
function pyp_period_open($date){global $db;if(!pyp_table_exists('erp_financial_period'))return true;$p=$db->fetch("SELECT status FROM erp_financial_period WHERE ? BETWEEN start_date AND end_date LIMIT 1",array($date));if(!$p)return 'Fiscal period untuk tanggal '.$date.' belum dibuat.';return $p->status==='OPEN'?true:'Fiscal period tanggal '.$date.' status '.$p->status.', tidak boleh posting.';}
function pyp_account_leaf($account,$label){global $db;$r=$db->fetch("SELECT r.no_rek,r.nama_rek FROM rekening r LEFT JOIN rekening c ON c.induk=r.no_rek WHERE r.no_rek=? AND c.no_rek IS NULL LIMIT 1",array($account));if(!$r)throw new Exception($label.' tidak valid atau bukan akun detail.');return $r;}
function pyp_row($id){global $db;return $db->fetch("SELECT pp.*,pr.process_status payroll_process_status,jh.no_jurnal FROM erp_payroll_posting pp JOIN erp_payroll_process pr ON pr.id=pp.payroll_process_id LEFT JOIN jurnal_header jh ON jh.id=pp.journal_header_id WHERE pp.id=? LIMIT 1",array((int)$id));}
function pyp_rows($from,$to,$area,$status,$variant,$kw){global $db;$w=" WHERE pp.posting_date BETWEEN ? AND ? ";$p=array($from,$to);if($area!==''){$w.=" AND pp.payroll_area=? ";$p[]=$area;}if($status!==''){$w.=" AND pp.posting_status=? ";$p[]=$status;}if($variant!==''){$w.=" AND pp.posting_variant=? ";$p[]=$variant;}if($kw!==''){$like='%'.$kw.'%';$w.=" AND (pp.posting_no LIKE ? OR pp.payroll_run_no LIKE ? OR pp.external_reference LIKE ? OR pp.sap_reference LIKE ?) ";array_push($p,$like,$like,$like,$like);}return $db->query("SELECT pp.*,jh.no_jurnal FROM erp_payroll_posting pp LEFT JOIN jurnal_header jh ON jh.id=pp.journal_header_id $w ORDER BY pp.posting_date DESC,pp.posting_no",$p);}
function pyp_generate_lines($postingId){global $db;$pp=$db->fetch("SELECT * FROM erp_payroll_posting WHERE id=? LIMIT 1",array((int)$postingId));if(!$pp)throw new Exception('Payroll Posting tidak ditemukan.');$db->delete('erp_payroll_posting_line','payroll_posting_id',$postingId);$lines=array(array(10,$pp->salary_expense_account,'DEBIT','Payroll gross expense '.$pp->payroll_run_no,(float)$pp->gross_amount,'GROSS'),array(20,$pp->payroll_payable_account,'CREDIT','Payroll net payable '.$pp->payroll_run_no,(float)$pp->net_amount,'NET'));if((float)$pp->tax_amount>0)$lines[]=array(30,$pp->tax_payable_account,'CREDIT','Payroll tax payable '.$pp->payroll_run_no,(float)$pp->tax_amount,'TAX');if((float)$pp->deduction_amount>0)$lines[]=array(40,$pp->deduction_payable_account,'CREDIT','Payroll deduction payable '.$pp->payroll_run_no,(float)$pp->deduction_amount,'DEDUCTION');foreach($lines as $l){$a=pyp_account_leaf($l[1],'Account '.$l[1]);if($l[4]<=0)continue;$db->insert('erp_payroll_posting_line',array('payroll_posting_id'=>$postingId,'line_no'=>$l[0],'account_no'=>$l[1],'account_name'=>$a->nama_rek,'posting_key'=>$l[2],'line_text'=>$l[3],'amount'=>$l[4],'currency'=>$pp->currency,'source_amount_type'=>$l[5]));}}
function pyp_post_gl($postingId){global $db;$pp=pyp_row($postingId);if(!$pp)throw new Exception('Payroll Posting tidak ditemukan.');if($pp->posting_status==='POSTED')throw new Exception('Payroll Posting sudah POSTED.');$period=pyp_period_open($pp->posting_date);if($period!==true)throw new Exception($period);foreach(array($pp->salary_expense_account=>'Salary expense account',$pp->payroll_payable_account=>'Payroll payable account',$pp->tax_payable_account=>'Tax payable account',$pp->deduction_payable_account=>'Deduction payable account') as $acc=>$label){if($acc!=='')pyp_account_leaf($acc,$label);}pyp_generate_lines($postingId);$lineStmt=$db->query("SELECT * FROM erp_payroll_posting_line WHERE payroll_posting_id=? ORDER BY line_no",array($postingId));$lines=array();$debit=0;$credit=0;foreach($lineStmt as $l){$lines[]=$l;if($l->posting_key==='DEBIT')$debit+=(float)$l->amount;else $credit+=(float)$l->amount;}if(!count($lines))throw new Exception('Posting line belum terbentuk.');if(abs($debit-$credit)>0.01)throw new Exception('Posting tidak balance. Debit '.number_format($debit,2).' Credit '.number_format($credit,2));$db->query("START TRANSACTION");try{if($pp->journal_header_id){$hid=$pp->journal_header_id;$db->delete('jurnal_detail','id_header',$hid);$db->update('jurnal_header',array('document_type'=>'PY','posting_status'=>'POSTED','tgl_jurnal'=>$pp->posting_date,'ket'=>'PAYROLL POSTING: '.$pp->payroll_run_no,'no_bukti'=>$pp->posting_no,'source_module'=>'PAYROLL_POSTING','source_document_no'=>$pp->posting_no,'username'=>pyp_user(),'posted_by'=>pyp_user(),'posted_at'=>date('Y-m-d H:i:s'),'updated_by'=>pyp_user(),'updated_at'=>date('Y-m-d H:i:s')),'id',$hid);}else{$db->insert('jurnal_header',array('no_jurnal'=>generate_no_jurnal(),'document_type'=>'PY','posting_status'=>'POSTED','tgl_jurnal'=>$pp->posting_date,'ket'=>'PAYROLL POSTING: '.$pp->payroll_run_no,'no_bukti'=>$pp->posting_no,'source_module'=>'PAYROLL_POSTING','source_document_no'=>$pp->posting_no,'username'=>pyp_user(),'posted_by'=>pyp_user(),'posted_at'=>date('Y-m-d H:i:s'),'tgl_insert'=>date('Y-m-d H:i:s')));$hid=$db->last_insert_id();}$ln=1;foreach($lines as $l){$ok=$db->insert('jurnal_detail',array('id_header'=>$hid,'line_no'=>$ln++,'no_rek'=>$l->account_no,'line_text'=>$l->line_text,'debet'=>$l->posting_key==='DEBIT'?(float)$l->amount:0,'kredit'=>$l->posting_key==='CREDIT'?(float)$l->amount:0,'valuta'=>$l->currency,'kurs'=>1));if(!$ok)throw new Exception($db->getErrorMessage()?:'Gagal insert detail jurnal payroll.');}$cnt=$db->fetch("SELECT COUNT(*) jml FROM jurnal_detail WHERE id_header=?",array($hid));if(!$cnt||(int)$cnt->jml<1)throw new Exception('Detail jurnal payroll kosong setelah posting.');$db->update('erp_payroll_posting',array('posting_status'=>'POSTED','journal_header_id'=>$hid,'posted_by'=>pyp_user(),'posted_at'=>date('Y-m-d H:i:s'),'updated_by'=>pyp_user(),'updated_at'=>date('Y-m-d H:i:s')),'id',$postingId);$db->update('erp_payroll_process',array('process_status'=>'POSTED','posted_by'=>pyp_user(),'posted_at'=>date('Y-m-d H:i:s'),'posting_reference'=>$pp->posting_no,'updated_by'=>pyp_user(),'updated_at'=>date('Y-m-d H:i:s')),'id',$pp->payroll_process_id);$db->query("COMMIT");return $hid;}catch(Exception $e){$db->query("ROLLBACK");throw $e;}}
$act=isset($_GET['act'])?$_GET['act']:'';$username=pyp_user();$variants=array('SUMMARY','BY_COST_CENTER','BY_EMPLOYEE');$stats=array('DRAFT','READY','POSTED','REVERSED','CANCELLED');$areas=array('MONTHLY','DAILY','WEEKLY','CONTRACT','MANAGEMENT','ALL');
switch($act){
case 'account_search':$t=trim(pyp_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT r.no_rek,r.nama_rek FROM rekening r LEFT JOIN rekening c ON c.induk=r.no_rek WHERE c.no_rek IS NULL AND (?='' OR r.no_rek LIKE ? OR r.nama_rek LIKE ?) ORDER BY r.no_rek LIMIT 40",array($t,$like,$like));pyp_select2($rows,'no_rek',function($r){return $r->no_rek.' - '.$r->nama_rek;});
case 'process_search':$t=trim(pyp_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT p.id,p.payroll_run_no,p.payroll_area,p.process_status,p.total_employee,p.total_net FROM erp_payroll_process p LEFT JOIN erp_payroll_posting pp ON pp.payroll_process_id=p.id AND pp.posting_status<>'CANCELLED' WHERE pp.id IS NULL AND p.process_status IN ('CALCULATED','APPROVED','POSTED') AND (?='' OR p.payroll_run_no LIKE ? OR p.payroll_area LIKE ?) ORDER BY p.period_year DESC,p.period_month DESC,p.payroll_run_no LIMIT 40",array($t,$like,$like));pyp_select2($rows,'id',function($r){return $r->payroll_run_no.' ['.$r->payroll_area.' / '.$r->process_status.' / Net '.number_format((float)$r->total_net,0).']';});
case 'process_info':$p=$db->fetch("SELECT * FROM erp_payroll_process WHERE id=? LIMIT 1",array((int)pyp_p('payroll_process_id')));if(!$p)pyp_json('error','Payroll Process tidak ditemukan.');pyp_json('good','',array('payroll_run_no'=>$p->payroll_run_no,'payroll_area'=>$p->payroll_area,'total_employee'=>$p->total_employee,'gross_amount'=>$p->total_gross,'deduction_amount'=>$p->total_deduction,'tax_amount'=>$p->total_tax,'net_amount'=>$p->total_net,'currency'=>$p->currency));
case 'get':$r=pyp_row((int)pyp_p('id'));if(!$r)pyp_json('error','Payroll Posting tidak ditemukan.');$d=(array)$r;$d['process_text']=$r->payroll_run_no.' ['.$r->payroll_area.' / Net '.number_format((float)$r->net_amount,0).']';foreach(array('salary_expense','payroll_payable','tax_payable','deduction_payable') as $x){$col=$x.'_account';$acc=$r->$col;$a=$acc?$db->fetch("SELECT nama_rek FROM rekening WHERE no_rek=? LIMIT 1",array($acc)):null;$d[$col.'_text']=$acc?($acc.' - '.($a?$a->nama_rek:'')):'';}$lines=$db->query("SELECT * FROM erp_payroll_posting_line WHERE payroll_posting_id=? ORDER BY line_no",array((int)$r->id));$d['lines']=array();foreach($lines as $l)$d['lines'][]=(array)$l;pyp_json('good','',array('data'=>$d));
case 'save':$id=(int)pyp_p('id');$postingNo=pyp_c(pyp_p('posting_no'));$processId=(int)pyp_p('payroll_process_id');$postingDate=trim(pyp_p('posting_date'));$docDate=trim(pyp_p('document_date'));$variant=pyp_c(pyp_p('posting_variant','SUMMARY'));$status=pyp_c(pyp_p('posting_status','DRAFT'));if($postingNo===''||!preg_match('/^[A-Z0-9_-]{4,40}$/',$postingNo))pyp_json('error','Posting No wajib valid.');if(!$processId)pyp_json('error','Payroll Process wajib dipilih.');if(!pyp_date_ok($postingDate)||!pyp_date_ok($docDate))pyp_json('error','Tanggal posting/document tidak valid.');if(!in_array($variant,$variants,true)||!in_array($status,$stats,true))pyp_json('error','Master posting tidak valid.');$pr=$db->fetch("SELECT * FROM erp_payroll_process WHERE id=? LIMIT 1",array($processId));if(!$pr)pyp_json('error','Payroll Process tidak ditemukan.');if($db->fetch("SELECT id FROM erp_payroll_posting WHERE posting_no=? AND id<>? LIMIT 1",array($postingNo,$id)))pyp_json('error','Posting No sudah digunakan.');if($db->fetch("SELECT id FROM erp_payroll_posting WHERE payroll_process_id=? AND id<>? AND posting_status<>'CANCELLED' LIMIT 1",array($processId,$id)))pyp_json('error','Payroll Process ini sudah punya posting aktif.');
  $salary=trim(pyp_p('salary_expense_account'));$payable=trim(pyp_p('payroll_payable_account'));$tax=trim(pyp_p('tax_payable_account'));$ded=trim(pyp_p('deduction_payable_account'));try{pyp_account_leaf($salary,'Salary expense account');pyp_account_leaf($payable,'Payroll payable account');if($tax!=='')pyp_account_leaf($tax,'Tax payable account');if($ded!=='')pyp_account_leaf($ded,'Deduction payable account');}catch(Exception $e){pyp_json('error',$e->getMessage());}
  $data=array('posting_no'=>$postingNo,'payroll_process_id'=>$pr->id,'payroll_run_no'=>$pr->payroll_run_no,'posting_date'=>$postingDate,'document_date'=>$docDate,'fiscal_year'=>(int)date('Y',strtotime($postingDate)),'fiscal_period'=>(int)date('n',strtotime($postingDate)),'document_type'=>pyp_c(pyp_p('document_type','PY')),'posting_variant'=>$variant,'posting_status'=>$status,'payroll_area'=>$pr->payroll_area,'total_employee'=>$pr->total_employee,'gross_amount'=>$pr->total_gross,'deduction_amount'=>$pr->total_deduction,'tax_amount'=>$pr->total_tax,'net_amount'=>$pr->total_net,'currency'=>$pr->currency,'salary_expense_account'=>$salary,'payroll_payable_account'=>$payable,'tax_payable_account'=>$tax?:null,'deduction_payable_account'=>$ded?:null,'external_reference'=>trim(pyp_p('external_reference')),'sap_reference'=>trim(pyp_p('sap_reference')),'remarks'=>trim(pyp_p('remarks')),'updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s'));
  if($id>0){$old=pyp_row($id);if(!$old)pyp_json('error','Payroll Posting tidak ditemukan.');if($old->posting_status==='POSTED')pyp_json('error','Payroll Posting POSTED tidak bisa diedit.');$ok=$db->update('erp_payroll_posting',$data,'id',$id);}else{$data['created_by']=$username;$ok=$db->insert('erp_payroll_posting',$data);$id=$db->last_insert_id();}if(!$ok)pyp_json('error',$db->getErrorMessage()?:'Payroll Posting gagal disimpan.');try{pyp_generate_lines($id);}catch(Exception $e){pyp_json('error',$e->getMessage());}if(function_exists('simpan_log'))simpan_log('User '.$username.' menyimpan Payroll Posting '.$postingNo.' untuk run '.$pr->payroll_run_no.' pada '.date('Y-m-d H:i:s'),$username);pyp_json('good','Payroll Posting berhasil disimpan.',array('id'=>$id));
case 'post':try{$id=(int)pyp_p('id');$hid=pyp_post_gl($id);if(function_exists('simpan_log'))simpan_log('User '.$username.' posting Payroll Posting ID '.$id.' ke jurnal '.$hid,$username);pyp_json('good','Payroll Posting berhasil diposting ke jurnal.',array('journal_header_id'=>$hid));}catch(Exception $e){pyp_json('error',$e->getMessage());}
case 'reverse':$id=(int)pyp_p('id');$pp=pyp_row($id);if(!$pp||$pp->posting_status!=='POSTED'||!$pp->journal_header_id)pyp_json('error','Hanya Payroll Posting POSTED yang bisa direversal.');$period=pyp_period_open(date('Y-m-d'));if($period!==true)pyp_json('error',$period);$lines=$db->query("SELECT * FROM jurnal_detail WHERE id_header=? ORDER BY line_no,id",array($pp->journal_header_id));$db->query("START TRANSACTION");try{$db->insert('jurnal_header',array('no_jurnal'=>generate_no_jurnal(),'document_type'=>'RV','posting_status'=>'POSTED','tgl_jurnal'=>date('Y-m-d'),'ket'=>'REVERSAL PAYROLL POSTING: '.$pp->posting_no,'no_bukti'=>'RV-'.$pp->posting_no,'source_module'=>'PAYROLL_POSTING_REVERSAL','source_document_no'=>$pp->posting_no,'reversal_of'=>$pp->journal_header_id,'username'=>$username,'posted_by'=>$username,'posted_at'=>date('Y-m-d H:i:s'),'tgl_insert'=>date('Y-m-d H:i:s')));$rev=$db->last_insert_id();$ln=1;foreach($lines as $l){$db->insert('jurnal_detail',array('id_header'=>$rev,'line_no'=>$ln++,'no_rek'=>$l->no_rek,'line_text'=>'Reversal '.$pp->posting_no,'debet'=>$l->kredit,'kredit'=>$l->debet,'valuta'=>$l->valuta,'kurs'=>$l->kurs));}$db->update('jurnal_header',array('posting_status'=>'REVERSED','updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s')),'id',$pp->journal_header_id);$db->update('erp_payroll_posting',array('posting_status'=>'REVERSED','reversal_journal_header_id'=>$rev,'reversed_by'=>$username,'reversed_at'=>date('Y-m-d H:i:s'),'updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s')),'id',$id);$db->update('erp_payroll_process',array('process_status'=>'CALCULATED','posting_reference'=>null,'updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s')),'id',$pp->payroll_process_id);$db->query("COMMIT");pyp_json('good','Payroll Posting berhasil direversal.');}catch(Exception $e){$db->query("ROLLBACK");pyp_json('error',$e->getMessage());}
