case 'detail':$r=pyp_row((int)pyp_p('id'));if(!$r){echo '<div class="alert alert-warning">Payroll Posting tidak ditemukan.</div>';break;}$lines=$db->query("SELECT l.*,rek.nama_rek FROM erp_payroll_posting_line l LEFT JOIN rekening rek ON rek.no_rek=l.account_no WHERE l.payroll_posting_id=? ORDER BY l.line_no",array((int)$r->id));$jr=$r->journal_header_id?$db->query("SELECT d.*,rek.nama_rek FROM jurnal_detail d LEFT JOIN rekening rek ON rek.no_rek=d.no_rek WHERE d.id_header=? ORDER BY d.line_no,d.id",array((int)$r->journal_header_id)):array();echo '<h3 style="margin-top:0">'.pyp_h($r->posting_no).' <small>'.pyp_h($r->payroll_run_no).'</small></h3><span class="label label-primary">'.pyp_h($r->payroll_area).'</span> <span class="label label-info">'.pyp_h($r->posting_variant).'</span> <span class="label label-success">'.pyp_h($r->posting_status).'</span><hr><div class="row"><div class="col-sm-3"><b>Posting Date</b><br>'.pyp_h($r->posting_date).'</div><div class="col-sm-3"><b>Journal</b><br>'.pyp_h($r->no_jurnal?:'-').'</div><div class="col-sm-3"><b>'.hr_h('hr_employee', 'Employee').'</b><br>'.(int)$r->total_employee.'</div><div class="col-sm-3"><b>'.hr_h('hr_net_pay', 'Net Pay').'</b><br>'.number_format((float)$r->net_amount,2).'</div></div><hr><h4>Posting Lines</h4><div class="table-responsive"><table class="table table-bordered table-condensed"><thead><tr><th>Line</th><th>Account</th><th>PK</th><th>Text</th><th class="text-right">Amount</th></tr></thead><tbody>';foreach($lines as $l){echo '<tr><td>'.(int)$l->line_no.'</td><td>'.pyp_h($l->account_no.' - '.($l->nama_rek?:$l->account_name)).'</td><td>'.pyp_h($l->posting_key).'</td><td>'.pyp_h($l->line_text).'</td><td class="text-right">'.number_format((float)$l->amount,2).'</td></tr>';}echo '</tbody></table></div>';if($r->journal_header_id){echo '<h4>Journal Detail</h4><div class="table-responsive"><table class="table table-bordered table-condensed"><thead><tr><th>Line</th><th>Account</th><th>Text</th><th class="text-rig